external_knowledge:
- "prolific reviewers" refers to reviewers who write many reviews;
- "more than a couple of reviews" refers to at least 3 reviews;
- "higher-than-average rating tendency" means their average rating is above 4.5.

sql:
SELECT year, COUNT(review_id) AS review_count
FROM reviews
GROUP BY year;

external_knowledge:
'John Smith' is known by his full name and is recognized as a single unique reviewer in the database;
'Usher Hall' refers to the specific venue where the shows took place;
The term 'shared his thoughts' refers to writing a review.

sql:
SELECT review_title, review_text
FROM reviews
WHERE CAST(SUBSTR(rating, 1, 1) AS INTEGER) < (SELECT AVG(CAST(SUBSTR(rating, 1, 1) AS INTEGER)) FROM reviews);
